const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, LevelFormat } = require('docx');
const fs = require('fs');

const doc = new Document({
  styles: {
    default: {
      document: {
        run: { font: "Arial", size: 24 }
      }
    },
    paragraphStyles: [
      {
        id: "Title",
        name: "Title",
        basedOn: "Normal",
        run: { size: 56, bold: true, color: "000000", font: "Arial" },
        paragraph: { spacing: { before: 240, after: 240 }, alignment: AlignmentType.CENTER }
      },
      {
        id: "Heading1",
        name: "Heading 1",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 32, bold: true, color: "000000", font: "Arial" },
        paragraph: { spacing: { before: 360, after: 180 }, outlineLevel: 0 }
      },
      {
        id: "Heading2",
        name: "Heading 2",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 28, bold: true, color: "000000", font: "Arial" },
        paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 1 }
      },
      {
        id: "Citation",
        name: "Citation",
        basedOn: "Normal",
        run: { size: 24, font: "Arial" },
        paragraph: { spacing: { before: 80, after: 80 }, indent: { left: 720, hanging: 360 } }
      },
      {
        id: "Annotation",
        name: "Annotation",
        basedOn: "Normal",
        run: { size: 24, font: "Arial" },
        paragraph: { spacing: { before: 80, after: 240 }, indent: { left: 720 } }
      }
    ]
  },
  numbering: {
    config: [
      {
        reference: "bullet-list",
        levels: [
          {
            level: 0,
            format: LevelFormat.BULLET,
            text: "•",
            alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 1080, hanging: 360 } } }
          }
        ]
      }
    ]
  },
  sections: [{
    properties: {
      page: {
        margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 }
      }
    },
    children: [
      new Paragraph({
        heading: HeadingLevel.TITLE,
        children: [new TextRun("주석이 달린 참고문헌")]
      }),

      new Paragraph({
        heading: HeadingLevel.TITLE,
        children: [new TextRun("온톨로지의 철학적 개념과 시맨틱 레이어")]
      }),

      new Paragraph({
        spacing: { before: 240, after: 360 },
        children: [new TextRun("이 주석이 달린 참고문헌은 온톨로지의 철학적 기초부터 현대 데이터 아키텍처에서 시맨틱 레이어의 실무적 응용까지, 두 개념의 이론적 배경과 실제 구현을 포괄적으로 다룹니다. 각 출처는 이 주제의 다양한 측면을 조명하며, 철학적 전통에서 현대 기술 솔루션으로의 진화를 보여줍니다.")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("I. 온톨로지의 철학적 개념")]
      }),

      // Entry 1
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Stanford Encyclopedia of Philosophy. (2025). Logic and Ontology. Retrieved December 12, 2025, from https://plato.stanford.edu/entries/logic-ontology/",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("이 자료는 논리학과 온톨로지 사이의 관계를 심도 있게 탐구하며, 특히 프레게(Frege)의 논리주의와 논리적 대상의 존재론적 함의를 다룹니다. 철학 백과사전으로서 학술적 권위를 갖추고 있으며, 논리적 진리가 어떻게 존재의 문제와 연결되는지에 대한 명확한 설명을 제공합니다. 온톨로지의 형식적 측면을 이해하는 데 필수적인 자료이며, 철학적 온톨로지에서 형식 온톨로지로 넘어가는 개념적 다리를 제공합니다.")]
      }),

      // Entry 2
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Wikipedia. (2025). Ontology. Retrieved December 12, 2025, from https://en.wikipedia.org/wiki/Ontology",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("온톨로지에 대한 포괄적이고 접근하기 쉬운 개요를 제공하며, 존재의 연구로서 온톨로지를 정의하고 형이상학의 하위 분야로서의 역할을 설명합니다. 보편자와 특수자, 구체적 대상과 추상적 대상의 구분과 같은 핵심 개념을 명확하게 제시합니다. 비학술적 독자들을 위한 입문 자료로 유용하며, 온톨로지의 다양한 방법론(개념 분석, 직관, 사고 실험, 자연과학 통합)을 체계적으로 소개합니다.")]
      }),

      // Entry 3
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Britannica. (2025). Ontology. Retrieved December 12, 2025, from https://www.britannica.com/topic/ontology-metaphysics",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("아리스토텔레스가 \"제1철학\"이라 명명한 온톨로지의 역사적 맥락을 제공하며, W.V.O. Quine에 의한 20세기 중반의 부활까지 그 발전을 추적합니다. 백과사전 항목으로서 신뢰할 수 있는 출처이며, 온톨로지의 근본적인 논쟁들(보편자 논쟁, 실재론 대 반실재론)을 역사적 관점에서 제시합니다. 철학사적 맥락에서 온톨로지를 이해하는 데 중요한 자료입니다.")]
      }),

      // Entry 4
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "New World Encyclopedia. (2025). Ontology. Retrieved December 12, 2025, from https://www.newworldencyclopedia.org/entry/Ontology",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("고대 그리스 철학에서 현대까지 온톨로지의 발전을 추적하며, 특히 파르메니데스와 헤라클레이토스의 존재와 변화에 대한 대조적 관점을 다룹니다. 아리스토텔레스의 개념적 구분과 중세 스콜라 철학, 그리고 Lorhard와 Goclenius의 용어 창안까지 포괄적으로 다룹니다. 동양 철학(Samkhya 학파)과의 비교도 포함하여, 온톨로지 개념의 보편성을 보여줍니다. 철학적 온톨로지의 문화적, 역사적 맥락을 이해하는 데 유용한 자료입니다.")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("II. 시맨틱 레이어: 개념과 아키텍처")]
      }),

      // Entry 5
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "IBM. (2025). What Is a Semantic Layer? Retrieved December 12, 2025, from https://www.ibm.com/think/topics/semantic-layer",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("IBM의 기업 관점에서 시맨틱 레이어를 정의하며, 복잡한 데이터 저장 시스템과 비즈니스 사용자 간의 인터페이스 역할을 강조합니다. 메타데이터의 중요성과 데이터 통합, 일관성 유지, 자가 서비스 분석의 촉진을 설명합니다. 기술 대기업의 권위 있는 관점을 제공하며, 실제 기업 환경에서의 적용 사례를 통해 시맨틱 레이어의 실용적 가치를 명확히 합니다.")]
      }),

      // Entry 6
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "DataCamp. (2025). What is a Semantic Layer? A Detailed Guide. Retrieved December 12, 2025, from https://www.datacamp.com/blog/semantic-layer",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("데이터 과학 교육 플랫폼의 관점에서 시맨틱 레이어를 설명하며, 기술적 데이터 구조와 사용자 요구 사이의 가교 역할을 강조합니다. 공통 비즈니스 어휘의 정의, 데이터 사일로 해결, 일관된 데이터 정의 보장 등의 핵심 기능을 다룹니다. 교육적 관점에서 작성되어 복잡한 개념을 이해하기 쉽게 설명하며, 메타데이터 우선 아키텍처와 같은 구현 방법론을 소개합니다.")]
      }),

      // Entry 7
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "dbt Labs. (2025). Understanding Semantic Layer Architecture. Retrieved December 12, 2025, from https://www.getdbt.com/blog/semantic-layer-architecture",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("현대 데이터 스택에서 시맨틱 레이어의 역할을 상세히 설명하며, 데이터 저장소(Snowflake, BigQuery)와 시각화 도구(Tableau, Power BI) 사이의 위치를 명확히 합니다. 일관된 메트릭 정의의 중요성을 실제 사례(고객 생애 가치 계산)를 통해 보여주며, 5가지 핵심 구성요소를 제시합니다. 실무 중심의 관점에서 작성되어 기술 팀이 시맨틱 레이어를 구현하는 데 직접적으로 유용한 지침을 제공합니다.")]
      }),

      // Entry 8
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Databricks. (2025). The Role of Semantic Layers in Modern Data Analytics. Retrieved December 12, 2025, from https://www.databricks.com/glossary/semantic-layer",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("시맨틱 레이어의 역사적 발전(1991년 Business Objects의 도입)부터 현대적 적용까지 추적하며, 클라우드 네이티브 아키텍처와 실시간 분석에 대한 적응을 설명합니다. 독립형 플랫폼(AtScale)과 통합형 솔루션의 비교를 제공하며, 메타데이터 관리, 쿼리 변환, 데이터 가상화 등의 작동 메커니즘을 상세히 다룹니다. 기업 데이터 아키텍처 내에서 시맨틱 레이어의 전략적 위치를 이해하는 데 중요한 자료입니다.")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("III. 온톨로지와 시맨틱 레이어의 통합")]
      }),

      // Entry 9
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Enterprise Knowledge. (2025). What's the Difference Between an Ontology and a Knowledge Graph? Retrieved December 12, 2025, from https://enterprise-knowledge.com/whats-the-difference-between-an-ontology-and-a-knowledge-graph/",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("온톨로지와 지식 그래프의 관계를 명확히 하며, 온톨로지가 일반화된 시맨틱 데이터 모델인 반면 지식 그래프는 그 모델을 인스턴스 데이터에 적용한 결과임을 설명합니다. 도서관 메타데이터를 예시로 사용하여 개념을 구체화하고, SPARQL을 통한 추론 기능을 소개합니다. 이론적 온톨로지 개념과 실용적 지식 표현 사이의 연결고리를 제공하며, 시맨틱 기술의 실제 응용을 이해하는 데 필수적입니다.")]
      }),

      // Entry 10
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Blindata. (2024). Modeling the Semantics of Data: Knowledge Graphs and Ontologies. Retrieved December 12, 2025, from https://blindata.io/blog/2024/ontologies-for-semantic-modeling/",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("대규모 언어 모델(LLM)과 AI 시대에 온톨로지의 부활을 논의하며, 온톨로지 주도 시맨틱 레이어가 미래 지향적 지식 아키텍처를 구축하는 방법을 설명합니다. 구체화된 지식 그래프와 가상화된 지식 그래프의 차이를 설명하고, 분산된 데이터 환경에서 온톨로지가 시맨틱 접착제 역할을 하는 방법을 강조합니다. 현대 AI 시스템에서 온톨로지의 중요성이 증가하고 있음을 보여주며, 데이터 거버넌스와 시맨틱 풍부성의 통합을 다룹니다.")]
      }),

      // Entry 11
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Ontotext. (2025). What Is a Semantic Layer. Retrieved December 12, 2025, from https://www.ontotext.com/knowledgehub/fundamentals/what-is-a-semantic-layer",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("지식 그래프 기술 관점에서 시맨틱 레이어를 정의하며, FAIR 원칙(발견 가능, 접근 가능, 상호 운용 가능, 재사용 가능)을 데이터 관리에 적용하는 방법을 설명합니다. 시맨틱 지식 허브와 시맨틱 데이터 패브릭이라는 두 가지 주요 설계 패턴을 제시하고, RAG(검색 증강 생성) 애플리케이션에서 지식 그래프가 데이터베이스 스키마보다 우수한 성능을 보이는 이유를 설명합니다. 시맨틱 기술이 현대 엔터프라이즈 AI에 미치는 영향을 이해하는 데 중요한 자료입니다.")]
      }),

      // Entry 12
      new Paragraph({
        style: "Citation",
        children: [new TextRun({
          text: "Databricks & Stardog. (2022). How to Use a Knowledge Graph to Power a Semantic Data Layer for Databricks. Retrieved December 12, 2025, from https://www.databricks.com/blog/2022/06/17/using-a-knowledge-graph-to-power-a-semantic-data-layer-for-databricks.html",
          bold: true
        })]
      }),

      new Paragraph({
        style: "Annotation",
        children: [new TextRun("Databricks와 Stardog의 통합을 통해 지식 그래프 기반 시맨틱 데이터 레이어를 구현하는 실제 사례를 제시합니다. 데이터 레이크하우스 아키텍처에서 시맨틱 레이어의 역할을 설명하고, 복잡한 다대다 관계를 모델링하는 지식 그래프의 이점을 강조합니다. 비즈니스 온톨로지가 어떻게 데이터를 \"문자열\"이 아닌 \"의미 있는 것\"으로 표현하는지 보여주며, 엔터프라이즈 데이터 패브릭 아키텍처 구축을 위한 실용적 가이드를 제공합니다.")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("결론")]
      }),

      new Paragraph({
        spacing: { before: 240, after: 120 },
        children: [new TextRun("이 참고문헌 모음은 온톨로지의 철학적 기초부터 시맨틱 레이어의 현대적 구현까지 포괄적인 이해를 제공합니다. 주요 통찰은 다음과 같습니다:")]
      }),

      new Paragraph({
        numbering: { reference: "bullet-list", level: 0 },
        children: [new TextRun({
          text: "철학적 온톨로지: 고대 그리스에서 현대 분석 철학까지의 발전을 추적하며, 존재, 보편자, 범주에 대한 근본적 질문을 탐구합니다."
        })]
      }),

      new Paragraph({
        numbering: { reference: "bullet-list", level: 0 },
        children: [new TextRun({
          text: "시맨틱 레이어: 복잡한 데이터 구조를 비즈니스 친화적 용어로 변환하고, 조직 전체에서 일관된 데이터 해석을 보장하는 현대 데이터 아키텍처의 핵심 구성요소입니다."
        })]
      }),

      new Paragraph({
        numbering: { reference: "bullet-list", level: 0 },
        children: [new TextRun({
          text: "통합 관점: 온톨로지는 시맨틱 레이어의 이론적 기초를 제공하며, 지식 그래프는 이 두 개념을 실제 응용으로 연결하는 다리 역할을 합니다."
        })]
      }),

      new Paragraph({
        numbering: { reference: "bullet-list", level: 0 },
        children: [new TextRun({
          text: "현대적 관련성: AI와 대규모 언어 모델의 시대에 온톨로지 주도 시맨틱 레이어는 데이터 품질, 일관성, 해석 가능성을 보장하는 데 점점 더 중요해지고 있습니다."
        })]
      }),

      new Paragraph({
        spacing: { before: 240, after: 120 },
        children: [new TextRun("이러한 자료들은 함께 철학적 사유에서 실용적 구현까지, 의미와 지식 표현에 대한 인간의 탐구가 어떻게 진화해왔는지 보여줍니다. 온톨로지가 제공하는 개념적 명확성과 시맨틱 레이어가 가능하게 하는 기술적 실현은 현대 지식 관리와 데이터 거버넌스의 기초를 형성합니다.")]
      })
    ]
  }]
